parameters.jsCode:
const now = new Date();
const y = now.getFullYear();
const deadlines = [
  { name: 'Self Assessment Tax Return + Payment', date: new Date(y, 0, 31), category: 'HMRC', urgency: 'critical', detail: 'Online Self Assessment filing AND any tax owed must be paid today.' },
  { name: 'VAT Return — Q1 (Oct-Dec)', date: new Date(y, 0, 31), category: 'VAT', urgency: 'high', detail: 'Submit and pay VAT for Oct-Dec quarter.' },
  { name: 'Corporation Tax Payment', date: new Date(y, 8, 30), category: 'HMRC', urgency: 'high', detail: 'Check your specific accounting year end — this is an approximation.' },
  { name: 'VAT Return — Q2 (Jan-Mar)', date: new Date(y, 3, 30), category: 'VAT', urgency: 'high', detail: 'Submit and pay VAT for Jan-Mar quarter.' },
  { name: 'VAT Return — Q3 (Apr-Jun)', date: new Date(y, 6, 31), category: 'VAT', urgency: 'high', detail: 'Submit and pay VAT for Apr-Jun quarter.' },
  { name: 'Second Payment on Account', date: new Date(y, 6, 31), category: 'HMRC', urgency: 'high', detail: 'Second payment on account for Self Assessment.' },
  { name: 'VAT Return — Q4 (Jul-Sep)', date: new Date(y, 9, 31), category: 'VAT', urgency: 'high', detail: 'Submit and pay VAT for Jul-Sep quarter.' },
  { name: 'PAYE Monthly Payment', date: new Date(y, now.getMonth(), 19), category: 'PAYE', urgency: 'medium', detail: 'Monthly PAYE and NI payment to HMRC.' },
  { name: 'PAYE Next Month', date: new Date(y, now.getMonth()+1, 19), category: 'PAYE', urgency: 'medium', detail: 'Next monthly PAYE and NI payment to HMRC.' },
  { name: 'Self Assessment Registration', date: new Date(y, 9, 5), category: 'HMRC', urgency: 'medium', detail: 'Deadline to register for Self Assessment if new to it.' }
];
const upcoming = deadlines.filter(d => {
  const days = Math.floor((d.date - now) / (1000*60*60*24));
  return days >= 0 && days <= 14;
}).map(d => ({ ...d, date: d.date.toISOString().split('T')[0], days_until: Math.floor((d.date - now) / (1000*60*60*24)) }));
if (upcoming.length === 0) return [];
const summary = upcoming.map(d => `• ${d.name} (${d.days_until}d) — ${d.detail}`).join('\n');
return [{ json: { deadlines: upcoming, count: upcoming.length, summary, urgent_count: upcoming.filter(d=>d.urgency==='critical').length } }];

